const items = $input.all();

// Procesar todos los items
const processedItems = items.map(item => {
  let respuestaAgente = item.json.output || "";

  // Intentar parsear el JSON
  let mensajeFinal = respuestaAgente;

  try {
    // Buscar el JSON en la respuesta
    const jsonMatch = respuestaAgente.match(/\{[\s\S]*"mensajeCliente"[\s\S]*\}/);

    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      mensajeFinal = parsed.mensajeCliente || respuestaAgente;
    }
  } catch (error) {
    // Si falla, usar texto completo
  }

  // Limpiar el mensaje
  mensajeFinal = mensajeFinal
    .replace(/\\n/g, '\n')
    .replace(/\\"/g, '"')
    .replace(/<[^>]*>/g, '')
    .trim();

  return {
    json: {
      mensajeLimpio: mensajeFinal,
      telefono: item.json.TELEFONO
    }
  };
});

// Devolver SOLO el primer item
return processedItems[0];

// Función para limpiar el número de teléfono
function cleanPhoneNumber(phoneString) {
  if (!phoneString || typeof phoneString !== 'string') {
    return phoneString;
  }

  // Eliminar todo excepto números
  // Esto quita @, guiones, espacios, puntos, etc.
  return phoneString.replace(/\D/g, '');
}

// Procesar todos los items
return $input.all().map(item => {
  const webhookData = item.json;

  // Crear una copia del objeto para no mutar el original
  const cleanedData = JSON.parse(JSON.stringify(webhookData));

  // Limpiar el número "from" (desde donde se envía)
  if (cleanedData.body?.data?.from) {
    cleanedData.body.data.from = cleanPhoneNumber(cleanedData.body.data.from);
  }

  // Limpiar el número "to" (a donde se recibe) si existe
  if (cleanedData.body?.data?.to) {
    cleanedData.body.data.to = cleanPhoneNumber(cleanedData.body.data.to);
  }

  // Limpiar el número en message._data.id.remote si existe
  if (cleanedData.body?.data?.message?._data?.id?.remote) {
    cleanedData.body.data.message._data.id.remote = cleanPhoneNumber(
      cleanedData.body.data.message._data.id.remote
    );
  }

  return {
    json: cleanedData
  };
});

const items = $input.all();

// Accedemos al nodo de mapeo
const dataMapeo = $('Mapeo de mensaje1').first().json;

// Priorizamos el campo 'audio' (transcripción) y si está vacío usamos 'mensaje' (texto directo)
const mensajeFinal = dataMapeo.audio || dataMapeo.mensaje || "";

return items.map(item => {
  const data = item.json;

  // Extraer datos con valores por defecto seguros
  const nombre = data.NOMBRE ? String(data.NOMBRE) : "Cliente";
  const telefono = data.TELEFONO ? String(data.TELEFONO) : "No disponible";
  const correo = data.CORREO ? String(data.CORREO) : "No disponible";
  const nPersonas = data.N_PERSONAS ? Number(data.N_PERSONAS) : 1;
  const idioma = data.IDIOMA ? String(data.IDIOMA) : "español";

  // Info de cita
  const estado = data.ESTADO ? String(data.ESTADO) : "sin cita";
  const fechaCita = data.FECHA_CITA ? String(data.FECHA_CITA) : "Sin cita agendada";
  const hora = data.HORA ? String(data.HORA) : "Sin hora definida";
  const eventId = data.EVENT_ID ? String(data.EVENT_ID) : null;

  // Info del club
  const club = data.CLUB ? String(data.CLUB) : "No especificado";
  const calendarId = data.CALENDAR_ID ? String(data.CALENDAR_ID) : "No disponible";
  const horario = data.HORARIO ? String(data.HORARIO) : "No disponible";
  const direccion = data.DIRECCION ? String(data.DIRECCION) : "No disponible";

  // Info adicional
  let infoAdicional = "No disponible";
  if (data["INFORMACION ADICIONAL "]) {
    infoAdicional = String(data["INFORMACION ADICIONAL "]);
  } else if (data.INFORMACION_ADICIONAL) {
    infoAdicional = String(data.INFORMACION_ADICIONAL);
  } else if (data["INFORMACIÓN ADICIONAL"]) {
    infoAdicional = String(data["INFORMACIÓN ADICIONAL"]);
  }

  // Formatear fecha
  let fechaCitaFormateada = fechaCita;
  if (fechaCita && fechaCita !== "Sin cita agendada" && fechaCita.includes('-')) {
    const partes = fechaCita.split('-');
    if (partes.length === 3) {
      fechaCitaFormateada = partes[2] + '/' + partes[1] + '/' + partes[0];
    }
  }

  const tieneCitaActiva = (estado.toLowerCase() === "activa" || estado.toLowerCase() === "active") && eventId !== null;
  const ahora = new Date();
  const fechaActualLegible = ahora.toLocaleString('es-ES', {
    timeZone: 'Europe/Madrid',
    weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
    hour: '2-digit', minute: '2-digit'
  });

  return {
    json: {
      NOMBRE: nombre,
      TELEFONO: telefono,
      CORREO: correo,
      N_PERSONAS: nPersonas,
      IDIOMA: idioma,
      ESTADO: estado,
      FECHA_CITA: fechaCitaFormateada,
      HORA: hora,
      EVENT_ID: eventId,
      TIENE_CITA_ACTIVA: tieneCitaActiva,
      CLUB: club,
      CALENDAR_ID: calendarId,
      HORARIO: horario,
      DIRECCION: direccion,
      INFORMACION_ADICIONAL: infoAdicional,
      FECHA_ACTUAL: ahora.toISOString(),
      FECHA_ACTUAL_LEGIBLE: fechaActualLegible,
      MENSAJE_USUARIO: mensajeFinal // <--- Aquí capturamos audio o mensaje
    }
  };
});
